Complete reference for working with PostgreSQL native arrays — creation, querying, manipulation, and aggregation.

```sql
-- Creation
SELECT ARRAY[1, 2, 3];                      -- {1,2,3}
SELECT ARRAY(SELECT id FROM users LIMIT 3);  -- from subquery
SELECT '{1,2,3}'::int[];                     -- cast from string
SELECT array_agg(name) FROM users;            -- from aggregation
SELECT string_to_array('a,b,c', ',');        -- split string

-- Querying
SELECT 1 = ANY(ARRAY[1,2,3]);     -- true (element exists)
SELECT 4 = ALL(ARRAY[4,4,4]);     -- true (all elements match)
SELECT ARRAY[1,2] <@ ARRAY[1,2,3]; -- true (contained in)
SELECT ARRAY[1,2,3] @> ARRAY[1,2]; -- true (contains)
SELECT ARRAY[1,2] && ARRAY[2,3];   -- true (overlap)

-- Manipulation
SELECT array_append(ARRAY[1,2], 3);          -- {1,2,3}
SELECT array_prepend(0, ARRAY[1,2]);         -- {0,1,2}
SELECT array_cat(ARRAY[1,2], ARRAY[3,4]);    -- {1,2,3,4}
SELECT array_remove(ARRAY[1,2,3,2], 2);      -- {1,3}
SELECT array_replace(ARRAY[1,2,3], 2, 20);   -- {1,20,3}
SELECT ARRAY[1,2,3] || ARRAY[4,5];           -- {1,2,3,4,5}
SELECT ARRAY[1,2,3] || 4;                     -- {1,2,3,4}

-- Info
SELECT array_length(ARRAY[1,2,3], 1);  -- 3
SELECT array_position(ARRAY['a','b','c'], 'b');  -- 2
SELECT cardinality(ARRAY[1,2,3]);  -- 3
SELECT array_dims(ARRAY[[1,2],[3,4]]);  -- [1:2][1:2]

-- Unnest (expand to rows)
SELECT unnest(ARRAY['a','b','c']);  -- 3 rows
SELECT * FROM unnest(ARRAY['a','b'], ARRAY[1,2]) AS t(letter, num);

-- Slice
SELECT (ARRAY[10,20,30,40,50])[2:4];  -- {20,30,40}

-- With GIN index for containment queries
CREATE INDEX idx_tags ON articles USING gin (tags);
SELECT * FROM articles WHERE tags @> ARRAY['python', 'tutorial'];
```
